--激活节点
function ModelHero:OnHeroTreePointActiveReq(upHeroList)
    local pb = LProtoHelper.CreateProto(LProtoIds.HeroTreePointActiveReq)

    pb.heroId = upHeroList.id
    pb.pointRefId = upHeroList.pointRefId

    local appointedlist = upHeroList.appointedlist
    for k, v in pairs(appointedlist) do
        for _k, id in pairs(v) do
            table.insert(pb.appoint, id)
        end
    end

    local rangelist = upHeroList.rangelist
    for k, v in pairs(rangelist) do
        for _k, id in pairs(v) do
            table.insert(pb.range, id)
        end
    end

    local items = pb.items
    local itemsList = upHeroList.rangItemList
    for i, v in pairs(itemsList) do
        for refId, num in pairs(v) do
            local tNum = tonumber(num)
            if tNum > 0 then
                local itemInfo = items:add()
                itemInfo.refId = tonumber(refId)
                itemInfo.num = tNum
            end
        end
    end

    SendMessage(pb, LProtoIds.HeroTreePointActiveReq)
end


