function ModelHero:InitHeroPointLvRef()
    local list = {}
    local type, tempSkillList
    local skillList = {}
    local heroTreePointLvRef = GameTable.CharacterTreePointLvRef
    for k, v in pairs(heroTreePointLvRef) do
        type = v.type
        if not list[type] then
            --数据基本结构
            list[type] = {
                pointType = nil,
                lvList = {},
            }
        end
        skillList = {}
        --节点增幅类型
        local pointType = list[type].pointType
        if not pointType then
            local setPointType = nil
            local next = v.next
            if next and next > 0 then
                local tempRef = heroTreePointLvRef[next]
                if tempRef then
                    if tempRef.skill and tempRef.skill ~= "" then
                        setPointType = ModelHero.TREE_POINT_TYPE_SKILL
                    elseif not string.isempty(tempRef.attr) then
                        setPointType = ModelHero.TREE_POINT_TYPE_ATTR
                    end
                end
            end
            --- 技能也会提升属性，所以先检查是否为空
            if v.skill and v.skill ~= "" then
                if not setPointType then
                    setPointType = ModelHero.TREE_POINT_TYPE_SKILL
                end
                local tSkillList = string.split(v.skill,"|")
                for idx,skillId in ipairs(tSkillList) do
                    skillId = checknumber(skillId)
                    table.insert(skillList, skillId)
                end
            elseif not string.isempty(v.attr) then
                if not setPointType then
                    setPointType = ModelHero.TREE_POINT_TYPE_ATTR
                end
            end
            list[type].pointType = setPointType
        end

        --节点列表
        table.insert(list[type].lvList, {
            refId = k,
            next = v.next,
            lv = v.lv,
            skillList = skillList,
        })
    end

    for k, v in pairs(list) do
        table.sort(v.lvList, function(a, b)
            return a.refId < b.refId
        end)
    end

    self._heroTreeLvList = list
end

