function ModelHero:GetHeroTreePointList(treeRefId)
    if not self._heroTreePointList[treeRefId] then
        local list = {}
        for k, v in pairs(GameTable.CharacterTreePointRef) do
            if v.type == treeRefId then
                table.insert(list, {
                    refId = v.refId,
                    sort = v.sort,
                })
            end
        end
        table.sort(list, function(a, b)
            return a.sort < b.sort
        end)
        self._heroTreePointList[treeRefId] = list
    end

    return self._heroTreePointList[treeRefId]
end

