function ModelHero:GetServerHeroTreePointInfo(heroId, treePointRefId)
    local serverData = gModelHero:GetHeroServerDataById(heroId)
    if not serverData then
        return nil
    end

    local treeInfo = serverData.treeInfo
    if not treeInfo then
        return nil
    end

    local points = treeInfo.points
    if not points then
        return nil
    end

    for k, v in ipairs(points) do
        local pointRefId = v.pointRefId
        if pointRefId == treePointRefId then
            return v
        end
    end

    printInfoNR(string.format("server point info is not find, heroId = %s, treePointRefId = %s", heroId, treePointRefId))
    return nil
end

function ModelHero:GetServerHeroTreeInfoByHeroId(heroId)
    local serverData = self:GetHeroServerDataById(heroId)
    if not serverData then
        return nil
    end
    local treeInfo = serverData.treeInfo
    if not treeInfo then
        printInfoNR("treeInfo is a nil")
        return nil
    end

    local treeRefId = treeInfo.treeRefId
    if treeRefId == 0 then
        return nil
    end

    local heroRefId = self:GetRefIdById(heroId)
    --- 当前激活的节点数据
    local treeInfoPoints = self:GetHeroServerTreePoints(heroId)
    local heroStar = self:GetHeroServerStar(heroId)
    local treeAllLvl = self:GetHeroServerTreeAllLvl(heroId)

    local treeInfoList = {}
    local treePointList = self:GetHeroTreePointList(treeRefId)
    for k, v in ipairs(treePointList) do
        local treePointRefId = v.refId
        local infoPoint = treeInfoPoints[treePointRefId]
        local isActivate = infoPoint ~= nil

        local lvRefId
        local canActivate,needConType,needActivateCon,firstConType,firstActivateCon
        local canLvlUp, needCon, needSelf, needRange, needItem, upLvlNeedConType, upLvlNeedActivateCon
        local curPointLv
        local nextLvRefId
        local isMaxLv
        local pointLvList = self:GetHeroTreePointLvList(treePointRefId)
        local pointType = pointLvList.pointType
        local lvList = pointLvList.lvList

        if not isActivate then
            --未激活
            local curPointRef = self:GetHeroTreePointRef(treePointRefId)

            local activityConType = curPointRef.conType
            local activateCon = curPointRef.activateCon
            canActivate, needConType, needActivateCon,firstConType,firstActivateCon = self:CheckTreePointCanActivateByTypeAndCon(activityConType, activateCon,
                    treeInfoPoints, heroStar)

            --未激活，需要检测节点是否能从0级（未激活） 升 》 1级（正式激活）
            local firstLvRef = lvList[1]
            lvRefId = firstLvRef.refId
        else
            --已激活
            lvRefId = infoPoint.lvRefId
        end

        local curPointLvRef = self:GetHeroTreePointLvRef(lvRefId)
        curPointLv = curPointLvRef.lv
        nextLvRefId = curPointLvRef.next
        isMaxLv = nextLvRefId <= 0
        if not isMaxLv then
            canLvlUp, isMaxLv, needCon, needSelf, needRange, needItem, upLvlNeedConType,
            upLvlNeedActivateCon = self:CheckTreePointCanUpLvlByRefId(lvRefId, treeAllLvl, heroStar, heroId, heroRefId)
        end

        local data = {
            isActivate = isActivate, --是否激活
            canActivate = canActivate, -- 是否可激活
            canLvlUp = canLvlUp, -- 可升级
            isMaxLv = isMaxLv, -- 是否满级
            treePointRefId = treePointRefId, -- 节点RefId
            lvRefId = lvRefId, --节点当前等级RefId
            nextLvRefId = nextLvRefId, --节点 关联下一级等级RefId
            needConType = needConType, --未激活时，没有达成的激活条件类型(只获取未通过的该类型)
            firstConType = firstConType, --未激活时，没有达成的激活条件类型(只获取未通过的该类型)
            firstActivateCon = firstActivateCon, --未激活时，没有达成的激活条件类型(只获取未通过的该类型)
            needActivateCon = needActivateCon, --未激活时，没有达成的激活条件
            curPointLv = curPointLv, -- 当前等级
            needCon = needCon, -- 升级所需条件 true = 未通过 ,false = 通过， nil = 不需要
            needSelf = needSelf, -- 升级所需本体 true = 未通过 ,false = 通过， nil = 不需要
            needRange = needRange, -- 升级所需范围 true = 未通过 ,false = 通过， nil = 不需要
            needItem = needItem, -- 升级所需道具 true = 未通过 ,false = 通过， nil = 不需要
            pointType = pointType, --节点类型 属性 or 技能
            lvList = lvList, --节点等级配置列表
            skillId = infoPoint and infoPoint.skillId or 0, --选择的技能id 0表示无技能或者未选择
            upLvlNeedConType = upLvlNeedConType, -- 当前继续升级条件类型
            upLvlNeedActivateCon = upLvlNeedActivateCon, -- 当前继续升级条件
            treeAllLvl = treeAllLvl, -- 当前技能树总等级
            treeRefId = treeRefId, -- 技能树refId
        }
        treeInfoList[treePointRefId] = data
    end

    return treeInfoList
end

function ModelHero:AttrList2AttrMap(attrList)
    local attrMap = {}
    attrList = attrList or {}
    local refId, type
    for i, v in ipairs(attrList) do
        refId = v.refId
        local attrRefIdMap = attrMap[refId]
        if not attrRefIdMap then
            attrRefIdMap = {}
            attrMap[refId] = attrRefIdMap
        end
        type = v.type
        local attrTypeNum = attrRefIdMap[type] or 0
        attrRefIdMap[type] = attrTypeNum + v.value
    end
    return attrMap
end

function ModelHero:GetAwakenTreePointAttrList(curPointAttr, nextPointAttr, isMaxLv)
    local curAttrList = self:GetAwakenTreePointAttrShiftList(curPointAttr)
    local nextAttrList = self:GetAwakenTreePointAttrShiftList(nextPointAttr)

    local isCanUpLv = not isMaxLv
    local list = {}
    local beforeAttrInfo, beforeAttrValue
    local isUp
    local curAttrMap = self:AttrList2AttrMap(curAttrList)
    local nextAttrMap = self:AttrList2AttrMap(nextAttrList)
    for refId, typeInfo in pairs(nextAttrMap) do
        for type, value in pairs(typeInfo) do
            beforeAttrInfo = curAttrMap[refId]
            beforeAttrValue = beforeAttrInfo and beforeAttrInfo[type] or 0
            isUp = isCanUpLv and value > beforeAttrValue or false
            table.insert(list, {
                refId = refId,
                type = type,
                value = beforeAttrValue,
                nextValue = value,
                isUp = isUp,
                isMaxLv = isMaxLv
            })
        end
    end
    table.sort(list, function(a, b)
        return gModelHero:GetAttributeSortById(a.refId) < gModelHero:GetAttributeSortById(b.refId)
    end)
    return list
end

function ModelHero:GetAwakenTreePointAttrShiftList(pointAttrStr)
    local attrList = string.split(pointAttrStr, ',')
    local shiftList = {}
    for k, v in ipairs(attrList) do
        local attr = string.split(v, '=')
        local data = {
            refId = tonumber(attr[1]),
            type = tonumber(attr[2]),
            value = tonumber(attr[3]),
        }

        table.insert(shiftList, data)
    end

    return shiftList
end

function ModelHero:GetAwakenFixReward(heroId)
    local rewardList = {}
    local serverData = gModelHero:GetHeroServerDataById(heroId)
    if not serverData then
        return rewardList
    end

    local treeInfo = serverData.treeInfo
    if not treeInfo then
        return rewardList
    end

    local points = treeInfo.points
    if not points then
        return rewardList
    end

    local heroRefId = self:GetRefIdById(heroId)

    for k, v in ipairs(points) do
        local pointRefId = v.pointRefId
        local lvRefId = v.lvRefId
        if pointRefId and pointRefId > 0 and lvRefId and lvRefId > 0 then
            local curPointRef = self:GetHeroTreePointLvRef(lvRefId)
            local fixReward = curPointRef.fixReward
            local fixRewardList = LxDataHelper.ParseItem(fixReward) or {}
            for key, itemData in ipairs(fixRewardList) do
                local itemId = itemData.itemId
                local itemNum = itemData.itemNum
                local itemType = itemData.itemType
                table.insert(rewardList, { refId = itemId, num = itemNum, itype = itemType })
            end

            local fixSelf = curPointRef.fixSelf
            if fixSelf and fixSelf > 0 then
                table.insert(rewardList, { refId = heroRefId, num = fixSelf, itype = LItemTypeConst.TYPE_HERO })
            end
        end
    end

    local ref
    local extraSkillCostRefId = treeInfo.extraSkillCostRefId or {}
    for k, v in pairs(extraSkillCostRefId) do
        ref = gModelHeroExtra:GetHeroExtraSkillCostRefByRefId(v)
        if ref then
            local fixReward = ref.fixReward
            local fixRewardList = LxDataHelper.ParseItem(fixReward) or {}
            for key, itemData in ipairs(fixRewardList) do
                local itemId = itemData.itemId
                local itemNum = itemData.itemNum
                local itemType = itemData.itemType
                table.insert(rewardList, { refId = itemId, num = itemNum, itype = itemType })
            end

            local fixSelf = ref.fixSelf
            if fixSelf and fixSelf > 0 then
                table.insert(rewardList, { refId = heroRefId, num = fixSelf, itype = LItemTypeConst.TYPE_HERO })
            end
        end
    end

    return rewardList
end

function ModelHero:GetTreePointSkillIdList(treePointRefId, skillIndex)
    local data = self:GetHeroTreePointLvList(treePointRefId)
    local pointType = data.pointType
    if pointType ~= ModelHero.TREE_POINT_TYPE_SKILL then
        printInfoNR("treePointRefId is not skill type, treePointRefId = " .. treePointRefId .. "; pointType = " .. pointType)
        return {}
    end

    local skillList = {}
    for k, v in ipairs(data.lvList) do
        local curPointLvRef = self:GetHeroTreePointLvRef(v.refId)
        local skillInfo = gModelHeroExtra:GetHeroTreeSkillList(curPointLvRef)
        local skills = {}
        for idx, val in ipairs(skillInfo.skill) do
            table.insert(skills, val)
        end
        for idx, val in ipairs(skillInfo.extraSkill or {}) do
            table.insert(skills, val)
        end
        local targetSkill = skills[skillIndex]
        if not string.isempty(targetSkill) then
            table.insert(skillList, tonumber(targetSkill))
        end
    end

    return skillList
end

function ModelHero:GetTreePointsCurLvAndMaxLv(treeInfo)
    local curLv, maxLv = 0, 0
    if not treeInfo then
        return curLv, maxLv
    end

    local treeRefId = treeInfo.treeRefId
    if treeRefId == 0 then
        return curLv, maxLv
    end

    local points = treeInfo.points
    if not points then
        return curLv, maxLv
    end

    local treeInfoPoints = {}
    for k, v in ipairs(points) do
        local pointRefId = v.pointRefId
        treeInfoPoints[pointRefId] = v
    end

    local treePointList = self:GetHeroTreePointList(treeRefId)
    for k, v in ipairs(treePointList) do
        local treePointRefId = v.refId

        local infoPoint = treeInfoPoints[treePointRefId]
        if infoPoint then
            local lvRefId = infoPoint.lvRefId
            local curPointLvRef = self:GetHeroTreePointLvRef(lvRefId)
            local curPointLv = curPointLvRef.lv
            curLv = curLv + curPointLv
        end

        local pointLvList = self:GetHeroTreePointLvList(treePointRefId)
        local lvList = pointLvList.lvList
        local maxLvListNum = #lvList
        local maxPointLvData = lvList[maxLvListNum]
        local maxPointLvRefId = maxPointLvData.refId
        local ref = gModelHero:GetHeroTreePointLvRef(maxPointLvRefId)
        local lv = ref.lv
        maxLv = maxLv + lv
    end
    return curLv, maxLv
end

function ModelHero:GetPreHeroTreeMaxLv(heroRefId)
    local curLv,maxLv = 0,0
    local heroAwaken = self:GetHeroAwakenByRefId(heroRefId)
    if heroAwaken and heroAwaken > 0 then
        local treePointList = self:GetHeroTreePointList(heroAwaken)
        if treePointList and #treePointList > 0 then
            for i,v in ipairs(treePointList) do
                local treePointRefId = v.refId
                local pointLvList = self:GetHeroTreePointLvList(treePointRefId)
                local lvList = pointLvList.lvList
                local maxLvListNum = #lvList
                local maxPointLvData = lvList[maxLvListNum]
                local maxPointLvRefId = maxPointLvData.refId
                local ref = self:GetHeroTreePointLvRef(maxPointLvRefId)
                maxLv = maxLv + ref.lv
            end
            curLv = maxLv
        end
    end
    return curLv,maxLv
end

function ModelHero:GetTreePointsLvlData(heroId)
    local serverData = self:GetHeroServerDataById(heroId)
    if not serverData then
        return 0, 0
    end

    local treeInfo = serverData.treeInfo
    if not treeInfo then
        printInfoNR("treeInfo is a nil")
        return 0, 0
    end

    local treeRefId = treeInfo.treeRefId
    if treeRefId == 0 then
        return 0, 0
    end

    local curLv, maxLv = 0, 0
    local treeInfoPoints = self:GetHeroServerTreePoints(heroId)
    local treePointList = self:GetHeroTreePointList(treeRefId)
    for k, v in ipairs(treePointList) do
        local treePointRefId = v.refId

        local infoPoint = treeInfoPoints[treePointRefId]
        if infoPoint then
            local lvRefId = infoPoint.lvRefId
            local curPointLvRef = self:GetHeroTreePointLvRef(lvRefId)
            local curPointLv = curPointLvRef.lv
            curLv = curLv + curPointLv
        end

        local pointLvList = self:GetHeroTreePointLvList(treePointRefId)
        local lvList = pointLvList.lvList
        local maxLvListNum = #lvList
        local maxPointLvData = lvList[maxLvListNum]
        local maxPointLvRefId = maxPointLvData.refId
        local ref = gModelHero:GetHeroTreePointLvRef(maxPointLvRefId)
        local lv = ref.lv
        maxLv = maxLv + lv
    end

    return curLv, maxLv
end

function ModelHero:GetAwakenIconPathByLvl(curLvl, isBig)
    local tempIndex = isBig and 0 or 4

    for k, v in ipairs(self._awakenIconLvlList) do
        if curLvl <= tonumber(v) then
            tempIndex = tempIndex + k
            break
        end
    end

    return self._awakenIconPath .. tempIndex
end

