function ModelHero:GetFakeMaxAwakenDataByRefId(treeRefId)
    local treeInfoList = {}
    local treePointList = self:GetHeroTreePointList(treeRefId)
    for k, v in ipairs(treePointList) do
        local treePointRefId = v.refId
        local pointLvList = self:GetHeroTreePointLvList(treePointRefId)
        local pointType = pointLvList.pointType
        local lvList = pointLvList.lvList

        local firstLvRef = lvList[#lvList] --默认满级
        local lvRefId = firstLvRef.refId

        local curPointLvRef = self:GetHeroTreePointLvRef(lvRefId)
        local curPointLv = curPointLvRef.lv
        local nextLvRefId = curPointLvRef.next
        local isMaxLv = nextLvRefId <= 0

        local skillId
        local skillList = {}
        if pointType == ModelHero.TREE_POINT_TYPE_SKILL then
            local pointSkill = curPointLvRef.skill
            if pointSkill and pointSkill ~= "" then
                local tList = string.split(pointSkill,"|")
                for i,val in ipairs(tList) do
                    table.insert(skillList,checknumber(v))
                end
            end
        end

        local data = {
            isActivate = true, --是否激活
            canActivate = nil, -- 是否可激活
            canLvlUp = nil, -- 可升级
            isMaxLv = isMaxLv, -- 是否满级
            treePointRefId = treePointRefId, -- 节点RefId
            lvRefId = lvRefId, --节点当前等级RefId
            nextLvRefId = nextLvRefId, --节点 关联下一级等级RefId
            needConType = nil, --未激活时，没有达成的激活条件类型(只获取未通过的该类型)
            needActivateCon = nil, --未激活时，没有达成的激活条件
            curPointLv = curPointLv, -- 当前等级
            needCon = nil, -- 升级所需条件 true = 未通过 ,false = 通过， nil = 不需要
            needSelf = nil, -- 升级所需本体 true = 未通过 ,false = 通过， nil = 不需要
            needRange = nil, -- 升级所需范围 true = 未通过 ,false = 通过， nil = 不需要
            needItem = nil, -- 升级所需道具 true = 未通过 ,false = 通过， nil = 不需要
            pointType = pointType, --节点类型 属性 or 技能
            lvList = lvList, --节点等级配置列表
            skillId = skillId or 0, --选择的技能id 0表示无技能或者未选择
            skillList = skillList,
            upLvlNeedConType = nil, -- 当前继续升级条件类型
            upLvlNeedActivateCon = nil, -- 当前继续升级条件
            treeAllLvl = nil, -- 当前技能树总等级
        }
        treeInfoList[treePointRefId] = data
    end

    return treeInfoList
end

-- 如果hType不为空，根据hType选英雄，否则根据hRefId和hStar
function ModelHero:AwakenFilterHero(hRefId, hStar, hType, selHeroId, selHeroList, needNum, isSelWnd)
    local filterList = {}
    -- 英雄筛选
    local heroList = self:GetHeroList()
    if heroList then
        local isSpiritHeroJoin
        local curAllLv, maxLv
        for k, v in pairs(heroList) do
            local data
            local id = v:GetId()
            local isTry = v:IsTryHero()
            isSpiritHeroJoin = false
            if gModelSpiritHero:CheckIsSpiritHero(v:GetRefId()) then
                --- 是否被链接，被链接的星灵英雄不加入
                isSpiritHeroJoin = gModelSpiritHero:CheckSpiritHeroIsHaveLink(v)
                ---------------------------------------------------------

                if not isSpiritHeroJoin then
                    curAllLv, maxLv = gModelHero:GetTreePointsLvlData(id)
                    if curAllLv and curAllLv > 0 then
                        --- 等级大于0的不能加入
                        isSpiritHeroJoin = true
                    end
                end
            end
            if id ~= selHeroId and not isTry and not isSpiritHeroJoin then
                local lock = v:GetLockStatus()
                local isJoin = isSelWnd or lock ~= 1
                if isJoin then
                    if hType then
                        local star = v:GetStar()
                        if hType == 0 and star == hStar then
                            if selHeroList[id] then
                                data = v
                            else
                                if not self:IsHeroIdUpLvTreeSel(id) then
                                    data = v
                                end
                            end
                        else
                            local refId = v:GetRefId()
                            local heroRef = self:GetHeroRef(refId)
                            if heroRef then
                                local rType = heroRef.raceType
                                if rType == hType and star == hStar then
                                    if selHeroList[id] then
                                        data = v
                                    else
                                        if not self:IsHeroIdUpLvTreeSel(id) then
                                            data = v
                                        end
                                    end
                                end
                            end
                        end
                    else
                        local refId = v:GetRefId()
                        local star = v:GetStar()
                        if refId == hRefId and star == hStar then
                            if selHeroList[id] then
                                data = v
                            else
                                if not self:IsHeroIdUpLvTreeSel(id) then
                                    data = v
                                end
                            end
                        end
                    end
                end
            end
            if data then
                filterList[k] = data
            end
        end
    end
    local serHeroRace
    if selHeroId then
        local refId = self:GetRefIdById(selHeroId)
        local ref = self:GetHeroRef(refId)
        if ref then
            serHeroRace = ref.raceType
        end
    end
    local itemList = {}
    if hType then
        -- 英魂筛选(道具)
        local bagYingHunList = gModelItem:GetBagYingHunList()
        for k, v in pairs(bagYingHunList) do
            local itemRefData = gModelItem:GetYingHunRefByRefId(k)
            if itemRefData then
                local isIns = false
                local refRace, refStar = itemRefData.race, itemRefData.star
                if serHeroRace and serHeroRace == refRace and refStar == hStar then
                    isIns = true
                elseif refRace == 0 and refStar == hStar then
                    isIns = true
                elseif (hType == 0 or refRace == hType) and refStar == hStar then
                    -- 填0时为任意种族都可以
                    isIns = true
                elseif refStar == hStar then
                    local other = ModelItem.RaceTypeList[refRace]
                    isIns = other and other[hType] or false
                end
                if isIns then
                    local itemStruct = gModelItem:GetItemServerDataByRefId(k)
                    if itemStruct then
                        local num = itemStruct._num
                        for i = 1, num do
                            if needNum and needNum < i then
                                break
                            end
                            local key = "itemRace_" .. refRace .. "_" .. i
                            itemList[key] = itemStruct
                        end
                    end
                end
            end
        end
    end
    return filterList, itemList
end

-- true:选中了 false:没选中
function ModelHero:IsHeroIdUpLvTreeSel(id)
    local selHeroList = self._upTreeLvSelHero
    if table.isempty(selHeroList) then
        return false
    end
    if selHeroList[id] then
        return true
    else
        return false
    end
end

function ModelHero:CheckTreePointCanActivateByTypeAndCon(conType, activateCon, treeInfoPoints, heroStar)
    local canActivate = true
    local needConType,needActivateCon = nil,nil
    local firstConType,firstActivateCon = nil
    local resonanceLv = gModelResonance:GetResonanceLv()
    local conTypes = string.split(conType, '|')
    local activateCons = string.split(activateCon, '|')
    for k, v in ipairs(conTypes) do
        if not string.isempty(v) then
            local curConType = tonumber(v)
            firstConType = curConType
            local curActivateCons = string.split(activateCons[k], ';')
            for p, q in ipairs(curActivateCons) do
                if not string.isempty(q) then
                    canActivate = canActivate and true or false
                    if curConType == ModelHero.TREE_CON_TYPE_LVL then
                        if not treeInfoPoints then
                            LogError("treeInfoPoints is a nil")
                            return false, nil, nil
                        end

                        local targetData = string.split(q, '=')
                        local targetPointRefId = tonumber(targetData[1])
                        local needPointLv = tonumber(targetData[2])
                        local treeInfoPoint = treeInfoPoints[targetPointRefId]
                        local lv = 0
                        if treeInfoPoint then
                            local lvRefId = treeInfoPoint.lvRefId
                            local treePointLvRef = self:GetHeroTreePointLvRef(lvRefId)
                            lv = treePointLvRef.lv
                        end
                        firstActivateCon = q
                        if lv < needPointLv then
                            canActivate = false
                            needConType = curConType
                            needActivateCon = q
                            break
                        end

                    elseif curConType == ModelHero.TREE_CON_TYPE_STAR then
                        firstActivateCon = q
                        if not heroStar or heroStar < tonumber(q) then
                            canActivate = false
                            needConType = curConType
                            needActivateCon = q
                            break
                        end
                    elseif curConType == ModelHero.TREE_CON_TYPE_RESONANCE then
                        firstActivateCon = q
                        if resonanceLv < tonumber(q) then
                            canActivate = false
                            needConType = curConType
                            needActivateCon = q
                            break
                        end
                    end
                end
            end

            if not canActivate then
                break
            end
        end
    end

    return canActivate, needConType, needActivateCon,firstConType,firstActivateCon
end

function ModelHero:CheckTreePointCanUpLvlByRefId(pointLvRefId, treeAllLvl, heroStar, heroId, hereRefId)
    local canLvlUp, isMax, needCon, needSelf, needRange, needItem, needConType, needActivateCon = false, nil, nil, nil, nil, nil, nil, nil
    local ref = self:GetHeroTreePointLvRef(pointLvRefId)

    -- 是否满级
    isMax = not self:CheckHeroTreeCanUpLvl(ref)
    if isMax then
        return canLvlUp, isMax, needCon, needSelf, needRange, needItem, needConType, needActivateCon
    end

    --升级前提条件
    needCon = true
    local conType = ref.conType
    local condition = ref.condition
    local conTypes = string.split(conType, '|')
    local conditions = string.split(condition, '|')
    local canActivate = true
    for k, v in ipairs(conTypes) do
        if not string.isempty(v) then
            local curConType = tonumber(v)
            local curActivateCons = string.split(conditions[k], ';')
            for p, q in ipairs(curActivateCons) do
                if not string.isempty(q) then
                    local curNeedActivateCon = tonumber(q)
                    if curConType == ModelHero.TREE_LV_CON_TYPE_LVL then
                        --技能树等级总和
                        if not treeAllLvl or curNeedActivateCon > treeAllLvl then
                            canActivate = false
                            needConType = curConType
                            needActivateCon = curNeedActivateCon
                            break
                        end
                    elseif curConType == ModelHero.TREE_LV_CON_TYPE_STAR then
                        --英雄达到星级
                        if not heroStar or curNeedActivateCon > heroStar then
                            canActivate = false
                            needConType = curConType
                            needActivateCon = curNeedActivateCon
                        end
                    elseif curConType == ModelHero.TREE_LV_CON_TYPE_RESONANCE then
                        -- 共鸣水晶等级
                        local resonanceLv = gModelResonance:GetResonanceLv()
                        if curNeedActivateCon > resonanceLv then
                            canActivate = false
                            needConType = curConType
                            needActivateCon = curNeedActivateCon
                        end
                    end
                end
            end
        end
    end

    if not canActivate then
        return canLvlUp, isMax, needCon, needSelf, needRange, needItem, needConType, needActivateCon
    end
    needCon = false

    local curSelHeroMap = {}
    --本体消耗, 默认5星
    local haveNum
    needSelf = true
    local upSelf = ref.upSelf
    if not string.isempty(upSelf) then
        local theroStar, needNum
        local upSelfInfos = string.split(upSelf, ",")
        for i, v in ipairs(upSelfInfos) do
            v = string.split(v, "=")
            needNum = tonumber(v[1])
            theroStar = tonumber(v[2])
            local selHeroNum = 0
            local resDataList = self:AwakenFilterHero(hereRefId, theroStar, nil, heroId, {})
            for key,val in pairs(resDataList) do
                if selHeroNum >= needNum then break end
                if not curSelHeroMap[key] then
                    curSelHeroMap[key] = val
                    selHeroNum = selHeroNum + 1
                end
            end
            haveNum = selHeroNum
            if haveNum < needNum then
                return canLvlUp, isMax, needCon, needSelf, needRange, needItem
            end
        end
    end
    needSelf = false

    -- 范围消耗
    needRange = true
    local upRange = ref.upRange
    if not string.isempty(upRange) then
        local upRanges = string.split(upRange, ',')
        for k, v in ipairs(upRanges) do
            local rangeData = string.split(v, '=')
            local rangType, rangeStar, rangeNum = tonumber(rangeData[1]), tonumber(rangeData[2]), tonumber(rangeData[3])
            local dataList, yinghunItemList = self:AwakenFilterHero(rangType, rangeStar, rangType, heroId, {})
            local selHeroNum = 0
            for key,val in pairs(dataList) do
                if selHeroNum >= haveNum then break end
                if not curSelHeroMap[key] then
                    curSelHeroMap[key] = val
                    selHeroNum = selHeroNum + 1
                end
            end
            haveNum = selHeroNum + #yinghunItemList
            if haveNum < rangeNum then
                return canLvlUp, isMax, needCon, needSelf, needRange, needItem
            end
        end
    end
    needRange = false

    -- 道具消耗
    needItem = true
    local upItem = ref.upItem
    if not string.isempty(upItem) then
        local upItems = string.split(upItem, ',')
        for k, v in ipairs(upItems) do
            local itemData = string.split(v, '=')
            local itemId, itemNum = tonumber(itemData[2]), tonumber(itemData[3])
            haveNum = gModelItem:GetNumByRefId(itemId)
            if haveNum < itemNum then
                return canLvlUp, isMax, needCon, needSelf, needRange, needItem
            end
        end
    end
    needItem = false
    canLvlUp = true

    return canLvlUp, isMax, needCon, needSelf, needRange, needItem
end

function ModelHero:CheckHeroAwakenTreeActivateOrUpLv(heroId)
    if not gModelFunctionOpen:CheckIsOpened(10306001, false) then
        return
    end

    local serverData = gModelHero:GetHeroServerDataById(heroId)
    if not serverData then
        return false
    end

    local heroStar = serverData.star
    local heroAwaken = gModelHero:GeConfigByKey("heroAwaken")
    local isShowAwaken = heroAwaken <= heroStar
    if not isShowAwaken then
        return false
    end

    local treeInfo = serverData.treeInfo
    if not treeInfo then
        return false
    end

    local treeRefId = treeInfo.treeRefId
    if treeRefId == 0 then
        return false
    end

    local heroRefId = self:GetRefIdById(heroId)
    local treeInfoPoints = self:GetHeroServerTreePoints(heroId) or {}
    local maxTreeRefId = 0
    for k,v in pairs(treeInfoPoints) do
        if v.lvRefId > maxTreeRefId then
            maxTreeRefId = v.lvRefId
        end
    end
    local treeAllLvl = self:GetHeroServerTreeAllLvl(heroId)

    local treePointList = self:GetHeroTreePointList(treeRefId)
    for k, v in ipairs(treePointList) do
        local treePointRefId = v.refId
        local infoPoint = treeInfoPoints[treePointRefId]
        local isActivate = infoPoint ~= nil
        local pointLvList = self:GetHeroTreePointLvList(treePointRefId)
        local lvList = pointLvList.lvList
        local lvRefId
        local canActivate
        --- 是否有下一级可升，目前为单线升级
        local hasNextLv = false
        if isActivate then
            --已激活
            local curPointLvRef = self:GetHeroTreePointLvRef(infoPoint.lvRefId)
            if curPointLvRef and curPointLvRef.next > 0 then
                hasNextLv = true
                lvRefId = infoPoint.lvRefId
            end
        else
            --未激活
            local curPointRef = self:GetHeroTreePointRef(treePointRefId)
            local activityConType = curPointRef.conType
            local activateCon = curPointRef.activateCon
            canActivate = self:CheckTreePointCanActivateByTypeAndCon(activityConType, activateCon,treeInfoPoints, heroStar)
            if canActivate then
                --未激活, 但满足激活条件，需要检测节点是否能从0级（未激活） 升 》 1级（正式激活）
                local firstLvRef = lvList[1]
                lvRefId = firstLvRef.refId
            end
        end
        if lvRefId and lvRefId > 0 then
            local curPointLvRef = self:GetHeroTreePointLvRef(lvRefId)
            if curPointLvRef then
                if curPointLvRef.refId > maxTreeRefId or hasNextLv then
                    local isCanUpLv = self:CheckHeroTreeCanUpLvl(curPointLvRef)
                    if isCanUpLv then
                        --未满级，检测升级消耗
                        local canLvlUp = self:CheckTreePointCanUpLvlByRefId(lvRefId, treeAllLvl, heroStar, heroId, heroRefId)
                        if canLvlUp then
                            return true
                        end
                    end
                    if not hasNextLv then
                        --- 单线成长，若无可升级，直接返回
                        return false
                    end
                end
            end
        end
  --[[      local treePointRefId = v.refId
        local infoPoint = treeInfoPoints[treePointRefId]
        local isActivate = infoPoint ~= nil
        local pointLvList = self:GetHeroTreePointLvList(treePointRefId)
        local lvList = pointLvList.lvList
        local lvRefId
        local canActivate
        if not isActivate then
            --未激活
            local curPointRef = self:GetHeroTreePointRef(treePointRefId)

            local activityConType = curPointRef.conType
            local activateCon = curPointRef.activateCon
            canActivate = self:CheckTreePointCanActivateByTypeAndCon(activityConType, activateCon,
                    treeInfoPoints, heroStar)

            if canActivate then
                --未激活, 但满足激活条件，需要检测节点是否能从0级（未激活） 升 》 1级（正式激活）
                local firstLvRef = lvList[1]
                lvRefId = firstLvRef.refId
            end
        else
            --已激活
            local curPointLvRef = self:GetHeroTreePointLvRef(infoPoint.lvRefId)
            if curPointLvRef and curPointLvRef.next > 0 then
                lvRefId = infoPoint.lvRefId
            end
        end

        if lvRefId then
            local curPointLvRef = self:GetHeroTreePointLvRef(lvRefId)
            local isCanUpLv = self:CheckHeroTreeCanUpLvl(curPointLvRef)
            if isCanUpLv then
                --未满级，检测升级消耗
                local canLvlUp = self:CheckTreePointCanUpLvlByRefId(lvRefId, treeAllLvl, heroStar, heroId, heroRefId)
                if canLvlUp then
                    return true
                end
            end

            local canLvlUp, needCon, needSelf, needRange, needItem, upLvlNeedConType, upLvlNeedActivateCon
            if isCanUpLv then
                canLvlUp, isCanUpLv, needCon, needSelf, needRange, needItem, upLvlNeedConType,
                upLvlNeedActivateCon = self:CheckTreePointCanUpLvlByRefId(lvRefId, treeAllLvl, heroStar, heroId, heroRefId)
            end
        end]]
    end

    if gModelHeroExtra:CheckHeroTreeIsHaveExtraSkillActByHeroServerData(serverData) then
        return true
    end

    return false
end

---@param curPointLvRef V_HeroTreePointLvRef 当前是否可以升级
function ModelHero:CheckHeroTreeCanUpLvl(curPointLvRef)
    return not string.isempty(curPointLvRef.upSelf) or
            not string.isempty(curPointLvRef.upRange) or
            not string.isempty(curPointLvRef.upItem)
end

function ModelHero:ClearUpLvTreeSelHeroList()
    printInfoNR("清空觉醒升级选项")
    self._upTreeLvSelHero = {}
end

function ModelHero:GetHeroTreePointLvListByType(lvType)
    if not self._heroTreeLvList[lvType] then
        return
    end
    return self._heroTreeLvList[lvType]
end

--- 是否可以开启觉醒
function ModelHero:CheckHeroIsCanAwaken(refId)
    local maxStar = self:GetMaxStarByRefId(refId)
    local heroAwaken = self:GeConfigByKey("heroAwaken")
    return maxStar >= heroAwaken
end